effect.shader:
#define DEG2RAD 0.01745329251994329576923690768489

vec2 l2s( vec2 v ) {
    return (vec4(v,0.,1.)*acLayerToScreen).xy;
}

vec2 bend(vec2 p, float a, float l, float w, bool vertical) {

   if( abs(a)<0.001 )
   {
       float v = p.y;
       p.y -= clamp(p.y,0.0,l);
       return vec2(p.x, v);
   }

   vec2  sc = vec2(sin(a),cos(a));

   if(vertical) {
       float ra = 0.5*l/a;
       p.x -= ra;
       float s = sign(a);
       float u = abs(ra)-length(p);
       float v = ra*atan(s*p.y,-s*p.x);
       u *= s;
       return vec2(u, v);
   }
   else {
       float ra = 0.5*w/a;
       p.y -= ra;
       float s = sign(a);
       float v = abs(ra)-length(p);
       float u = ra*atan(s*p.x,-s*p.y);
       v *= s;
       return vec2(u, v);

   }
}

void main() {

    vec2 a;
    vec2 b;
    vec2 c = vec2(0);
    bool vertical;
    float angleVal = amount;
    float originOffset = offset;
    float adjOffset = offset * 0.99;
    if( originType==0 ) {
        a = vec2(adjOffset,0.5);
        b = vec2(1.0,0.5);
        c = vec2(0.0, 0.5);

        vertical = false;
    } else if( originType==1 ) {
        a = vec2(1.0 - adjOffset,0.5);
        b = vec2(0.0,0.5);
        c = vec2(1.0, 0.5);
        vertical = false;
        angleVal = -amount;
    } else if( originType==2 ) {
        a = vec2(0.5,1.0 - adjOffset);
        b = vec2(0.5,0.0);
        c = vec2(0.5, 1.0);
        vertical = true;
    } else if( originType==3 ) {
        a = vec2(0.5,adjOffset);
        b = vec2(0.5,1.0);
        c = vec2(0.5, 0.0);
        vertical = true;
        angleVal = -amount;
    }

    vec2 a2b = b - a;
    vec2 a2c = acLayerNorm - a;
    float checkOffset = dot(a2b, a2c);
    if(checkOffset < 0.0) {
        if(oppositeType == 0 || adjOffset <= 0.0 ) {
            gl_FragColor = texture2DCv(inputImg.texture, acScreenNorm);
            return;
        }
        else {
            if(adjOffset < lowLimit)
                angleVal *= (adjOffset / lowLimit);
            b = c;
            a2b = b - a;
            angleVal = angleVal;
            if(oppositeType == 2)
                angleVal = -angleVal;
        }
    }
    else {

    if(adjOffset >= highLimit * 0.99)
        angleVal *= (1.0 - (adjOffset - highLimit * 0.99) / (0.99 - highLimit * 0.99));
    }

    angleVal = angleVal*DEG2RAD*0.5 / length(a2b);

    vec2 vv = acLayerNorm;
    vec2 av = a;
    if(vertical) {
        vv.x *= (acLayerSize.x/acLayerSize.y);
        av.x *= (acLayerSize.x/acLayerSize.y);
        vec2 uv = bend(vv-av,angleVal,1.0,1.0, vertical);
        uv.x *= acLayerSize.y/acLayerSize.x;
        av.x *= acLayerSize.y/acLayerSize.x;
        uv=l2s(uv+av);
        float insideTexture = step(0.0,uv.x) * step(uv.x,1.0) * step(0.0,uv.y) * step(uv.y,1.0);
        gl_FragColor = texture2DCv(inputImg.texture, uv) * insideTexture;
    }
    else {
        vv.y *= (acLayerSize.y/acLayerSize.x);
        av.y *= (acLayerSize.y/acLayerSize.x);
        vec2 uv = bend(vv-av,angleVal,1.0,1.0, vertical);
        uv.y *= acLayerSize.x/acLayerSize.y;
        av.y *= acLayerSize.x/acLayerSize.y;
        uv=l2s(uv+av);
        float insideTexture = step(0.0,uv.x) * step(uv.x,1.0) * step(0.0,uv.y) * step(uv.y,1.0);
        gl_FragColor = texture2DCv(inputImg.texture, uv) * insideTexture;
    }
}
